prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "2b18c5f00a5a46159c6cb6a3e2bc79e9") || CONTAINS(LCASE(STR(?modelName)), "2b18c5f00a5a46159c6cb6a3e2bc79e9"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?origId ?normId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:modelId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "2b18") || CONTAINS(LCASE(STR(?origId)), "2b18") || CONTAINS(LCASE(STR(?normId)), "2b18"))
}
LIMIT 10
